// Since N <= 5*10^4, we can use standard Ints for indices and distances. We cast N from Long to Int internally for array sizing.

def solve(nLong: Long, edges: Array[Array[Long]]): Long = {
    val n = nLong.toInt

    // parent[i]: parent of node i
    val parent = Array[Int](n)
    // dist[i]: parity of the path weight from i to parent[i] (0 or 1)
    val dist = Array[Int](n)

    // Initialization
    for (i <- 0 until n) {
        parent(i) = i
        dist(i) = 0
    }

    /**
     * Finds the root of i and performs path compression, updating distances along the way.
     * Returns the root R. After execution, dist[i] holds the parity of the path weight from i to R.
     * This function modifies the state (parent and dist arrays) globally.
     */
    def find(i: Int): Int = {
        if (parent(i) == i) {
            return i
        }

        // Recursively find the root R. This call updates parent[parent[i]] and dist[parent[i]]
        val root = find(parent(i))

        // Update distance for i: New dist[i] = old dist[i] XOR dist[parent[i]] (which now holds parity i_parent -> R)
        dist(i) = dist(i) xor dist(parent(i))

        // Path compression
        parent(i) = root
        root
    }

    var acceptedEdgesCount: Long = 0

    for (edge in edges) {
        // Input weights and node indices are provided as Longs, cast them to Ints for processing
        val u = edge(0).toInt
        val v = edge(1).toInt
        val w = edge(2).toInt // w is 0 or 1

        val rootU = find(u)
        val rootV = find(v)

        if (rootU != rootV) {
            // Case 1: u and v are in different components. Merge them (Union).

            // Merge rootU into rootV
            parent(rootU) = rootV

            // Calculate the new distance for rootU relative to rootV (dist[rootU] = parity R_U -> R_V).
            // Path R_U -> R_V = Path R_U -> u + Edge(u, v) + Path v -> R_V
            // Path R_U -> u has parity dist[u] (since paths are undirected)
            // Path v -> R_V has parity dist[v]
            // Parity = dist[u] XOR w XOR dist[v]
            dist(rootU) = dist(u) xor w xor dist(v)

            acceptedEdgesCount += 1
        } else {
            // Case 2: u and v are in the same component. Check for odd cycle creation.

            // Existing path parity P_uv = dist[u] XOR dist[v].
            val existingPathParity = dist(u) xor dist(v)

            // Cycle weight C = existingPathParity XOR w.
            // We accept if C is even (0). Condition: w == existingPathParity.

            if (w == existingPathParity) {
                // Edge accepted, maintains the even cycle property.
                acceptedEdgesCount += 1
            }
            // If w != existingPathParity, adding the edge creates an odd cycle, so we reject it.
        }
    }

