import scala.collection.mutable

object Solver {
    def solve(n: Long, edges: Array[Array[Long]]): Long = {
        val N = n.toInt

        // parent[i] stores the parent of i
        val parent = Array.fill[Int](N) { |i| i }
        // dist[i] = 0 or 1. Parity of path weight from i to parent[i].
        val dist = Array.fill[Int](N) { _ => 0 }

        // DSU Find operation with path compression and distance update
        def find(i: Int): (Int, Int) = { // Returns (root, parity_i_to_root)
            if (parent(i) == i) {
                (i, 0)
            } else {
                // Recurse to find root and distance of parent to root
                val (root, parentDistToRoot) = find(parent(i))

                // Update distance: new_dist[i] = old_dist[i] XOR parentDistToRoot
                // dist[i] holds parity i -> parent[i]
                // parentDistToRoot holds parity parent[i] -> root
                val newDistI = dist(i) xor parentDistToRoot

                // Path compression
                parent(i) = root
                dist(i) = newDistI

                (root, newDistI)
            }
        }

        var acceptedEdgesCount: Long = 0

        for (edge <- edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val w = edge(2).toInt // w is 0 or 1

            // Find roots and distances to roots
            val (rootU, distU) = find(u)
            val (rootV, distV) = find(v)

            if (rootU != rootV) {
                // Case 1: Different components. Merge them.

                // Union operation: Merge rootU into rootV
                parent(rootU) = rootV

