function solve(n, edges) {
    // DSU structure: parent[i] stores the parent of i, dist[i] stores the parity of the path weight from i to parent[i].
    const parent = Array(n).fill(0).map((_, i) => i);
    // dist[i] = 0 or 1. It represents the XOR sum of edge weights on the path from i to parent[i].
    const dist = Array(n).fill(0);

    /**
     * Finds the root of i and performs path compression, updating distances along the way.
     * Returns the root R. After execution, dist[i] holds the parity of the path weight from i to R.
     * @param {number} i
     * @returns {number} The root of the set containing i.
     */
    function find(i) {
        if (parent[i] === i) {
            return i;
        }

        const root = find(parent[i]);

        // Update distance: new_dist[i] = old_dist[i] XOR old_dist[parent[i]]
        // Where old_dist[parent[i]] is the path parity from parent[i] to root.
        dist[i] = dist[i] ^ dist[parent[i]];

        parent[i] = root;
        return root;
    }

    let acceptedEdgesCount = 0;

    for (const edge of edges) {
        const u = edge[0];
        const v = edge[1];
        const w = edge[2];

        const rootU = find(u);
        const rootV = find(v);

        if (rootU !== rootV) {
            // Case 1: u and v are in different components. Merge them.

            // Union operation: Merge rootU into rootV (arbitrary choice).
            parent[rootU] = rootV;

            // Calculate the new distance for rootU relative to rootV.
            // We know:
            // 1. Path u -> rootU has parity dist[u].
            // 2. Path v -> rootV has parity dist[v].
            // 3. We are adding edge u --(w)--> v.
            // We want dist[rootU] such that Path(rootU -> rootV) has the correct parity.
            // Path: rootU -> u --(w)--> v -> rootV
            // Parity = dist[u] ^ w ^ dist[v]
            dist[rootU] = dist[u] ^ w ^ dist[v];

